import xml.etree.ElementTree as ET
from xml.parsers.expat import ExpatError
import io

def validate_xml_file(file_content):
    """
    Validates an XML document uploaded by a user.
    
    Args:
        file_content (str or bytes): The content of the XML file
        
    Returns:
        tuple: (is_valid, error_message)
    """
    try:
        # If content is bytes, decode it to string
        if isinstance(file_content, bytes):
            file_content = file_content.decode('utf-8')
        
        # Parse the XML content
        root = ET.fromstring(file_content)
        
        # Basic validation - check if root element exists
        if root is None:
            return False, "Invalid XML: No root element found"
            
        # If we get here, XML is valid
        return True, "XML is valid"
        
    except ET.ParseError as e:
        return False, f"XML Parse Error: {str(e)}"
    except ExpatError as e:
        return False, f"XML Expat Error: {str(e)}"
    except UnicodeDecodeError as e:
        return False, f"Encoding Error: {str(e)}"
    except Exception as e:
        return False, f"Unexpected error: {str(e)}"

def validate_xml_file_from_path(file_path):
    """
    Validates an XML document from a file path.
    
    Args:
        file_path (str): Path to the XML file
        
    Returns:
        tuple: (is_valid, error_message)
    """
    try:
        # Parse the XML file
        tree = ET.parse(file_path)
        root = tree.getroot()
        
        # Basic validation
        if root is None:
            return False, "Invalid XML: No root element found"
            
        return True, "XML is valid"
        
    except ET.ParseError as e:
        return False, f"XML Parse Error: {str(e)}"
    except FileNotFoundError:
        return False, "File not found"
    except Exception as e:
        return False, f"Unexpected error: {str(e)}"